/**
 * \brief Retrieves the appropriate color based on the system's appearance (dark or light mode).
 *
 * This function checks the system's appearance settings and returns a color
 * string suitable for the current mode:
 * - White (#FFFFFF) for dark mode.
 * - Dark gray (#444444) for light mode.
 *
 * \return A `wxString` containing the color code.
 */
wxString vrBitmaps::GetColor() {
    wxSystemAppearance s = wxSystemSettings::GetAppearance();
    if (s.IsDark()) {
        return "#FFFFFF";  // White for dark mode
    }
    return "#444444";  // Dark gray for light mode
}

/**
 * \brief Retrieves the vroomGIS logo with the specified size and color.
 *
 * \param size The desired size of the logo, specified as a `wxSize` object.
 * \param colour The color to be used in the logo, specified as a `wxColour` object.
 * \return A `wxBitmap` object containing the logo.
 */
wxBitmap vrBitmaps::GetLogo(const wxSize& size, const wxColour& colour) {
    wxString my_bmp = wxString::Format(SvgLogo, colour.GetAsString(wxC2S_HTML_SYNTAX).ToStdString());
    return wxBitmapBundle::FromSVG(my_bmp, size).GetBitmap(size);
}

/**
 * \brief Retrieves a toolbar bitmap based on the specified toolbar ID and size.
 *
 * This function generates a bitmap for a toolbar icon by formatting an SVG string
 * with the appropriate color and converting it into a `wxBitmap` of the specified size.
 *
 * \param id The ID of the toolbar icon, represented by `vrBitmaps::ID_TOOLBAR`.
 * \param size The desired size of the bitmap, specified as a `wxSize` object.
 * \return A `wxBitmap` object containing the toolbar icon.
 */
wxBitmap vrBitmaps::GetToolbarBitmap(vrBitmaps::ID_TOOLBAR id, const wxSize& size) {
    wxString my_bmp = wxString::Format(SvgToolbar[id], GetColor().ToStdString());
    return wxBitmapBundle::FromSVG(my_bmp, size).GetBitmap(size);
}

/**
 * \brief Retrieves a table of contents (TOC) bitmap based on the specified TOC ID and size.
 *
 * This function generates a bitmap for a TOC icon by formatting an SVG string
 * with the appropriate color and converting it into a `wxBitmap` of the specified size.
 *
 * \param id The ID of the TOC icon, represented by `vrBitmaps::ID_TOC`.
 * \param size The desired size of the bitmap, specified as a `wxSize` object.
 * \return A `wxBitmap` object containing the TOC icon.
 */
wxBitmap vrBitmaps::GetTocBitmap(vrBitmaps::ID_TOC id, const wxSize& size) {
    wxString my_bmp = wxString::Format(SvgToc[id], GetColor().ToStdString());
    return wxBitmapBundle::FromSVG(my_bmp, size).GetBitmap(size);
}

wxBitmap vrBitmaps::GetCursorBitmap(vrBitmaps::ID_CURSORS id, const wxSize& size) {
    wxString my_bmp = wxString::Format(SvgCursors[id], "#000000");  // Default color for cursors
    return wxBitmapBundle::FromSVG(my_bmp, size).GetBitmap(size);
}
